import 'jsr:@supabase/functions-js/edge-runtime.d.ts'
import {
  ARTIST_TRACKS_LIMIT,
  fetchYtmAlbumTracks,
  fetchYtmArtistDetail,
  fetchYtmArtistTracks,
  fetchYtmCharts,
  fetchYtmDiscover,
  fetchYtmMoodPlaylists,
  fetchYtmPlaylistTracks,
  SEARCH_ALL_LIMIT,
  SEARCH_ARTIST_LIMIT,
  SEARCH_SONG_LIMIT,
  searchYtmAll,
  searchYtmArtists,
  searchYtmSongs,
  type YtmSearchResult,
} from './ytmusic.ts'

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers':
    'authorization, x-client-info, apikey, content-type',
}

type SearchType =
  | 'song'
  | 'artist'
  | 'all'
  | 'channel_tracks'
  | 'artist_detail'
  | 'album_tracks'
  | 'discover'
  | 'charts'
  | 'playlist_tracks'
  | 'mood_playlists'

function jsonResponse(body: unknown, status = 200) {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, 'Content-Type': 'application/json' },
  })
}

function parseRequest(req: Request): {
  q: string
  type: SearchType
  channelId?: string
  browseId?: string
} {
  const url = new URL(req.url)
  if (req.method === 'GET') {
    return {
      q: url.searchParams.get('q')?.trim() ?? '',
      type: (url.searchParams.get('type') as SearchType) ?? 'all',
      channelId: url.searchParams.get('channelId') ?? undefined,
      browseId: url.searchParams.get('browseId') ?? undefined,
    }
  }

  return {
    q: '',
    type: 'all',
  }
}

async function parseBody(req: Request): Promise<{
  q: string
  type: SearchType
  channelId?: string
  browseId?: string
  country?: string
  params?: string
  limit?: number
}> {
  if (req.method === 'GET') {
    return parseRequest(req)
  }

  try {
    const body = (await req.json()) as {
      q?: string
      type?: SearchType
      channelId?: string
      browseId?: string
      country?: string
      params?: string
      limit?: number
    }
    return {
      q: body.q?.trim() ?? '',
      type: body.type ?? 'all',
      channelId: body.channelId,
      browseId: body.browseId,
      country: body.country,
      params: body.params,
      limit:
        typeof body.limit === 'number' && body.limit > 0
          ? Math.min(body.limit, 100)
          : undefined,
    }
  } catch {
    return parseRequest(req)
  }
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const { q, type, channelId, browseId, country, params, limit } =
      await parseBody(req)

    if (type === 'discover') {
      const discover = await fetchYtmDiscover(country ?? 'ZZ')
      return jsonResponse(discover)
    }

    if (type === 'charts') {
      const charts = await fetchYtmCharts(country ?? 'ZZ')
      return jsonResponse(charts)
    }

    if (type === 'playlist_tracks') {
      if (!browseId) {
        return jsonResponse({ error: 'browseId is required' }, 400)
      }
      const results = await fetchYtmPlaylistTracks(browseId)
      return jsonResponse({ results })
    }

    if (type === 'mood_playlists') {
      if (!params) {
        return jsonResponse({ error: 'params is required' }, 400)
      }
      const playlists = await fetchYtmMoodPlaylists(params)
      return jsonResponse({ playlists })
    }

    if (type === 'channel_tracks') {
      if (!channelId) {
        return jsonResponse({ error: 'channelId is required' }, 400)
      }
      const results = await fetchYtmArtistTracks(
        channelId,
        limit ?? ARTIST_TRACKS_LIMIT,
      )
      return jsonResponse({ results })
    }

    if (type === 'artist_detail') {
      const id = browseId ?? channelId
      if (!id) {
        return jsonResponse({ error: 'browseId is required' }, 400)
      }
      const artist = await fetchYtmArtistDetail(id)
      return jsonResponse({ artist })
    }

    if (type === 'album_tracks') {
      if (!browseId) {
        return jsonResponse({ error: 'browseId is required' }, 400)
      }
      const results = await fetchYtmAlbumTracks(browseId)
      return jsonResponse({ results })
    }

    if (q.length < 2) {
      return jsonResponse({ results: [] })
    }

    let results: YtmSearchResult[] = []
    if (type === 'artist') {
      results = await searchYtmArtists(q, limit ?? SEARCH_ARTIST_LIMIT)
    } else if (type === 'song') {
      results = await searchYtmSongs(q, limit ?? SEARCH_SONG_LIMIT)
    } else {
      results = await searchYtmAll(q, limit ?? SEARCH_ALL_LIMIT)
    }

    return jsonResponse({ results })
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Search failed'
    return jsonResponse({ error: message }, 502)
  }
})

/** YouTube Music Innertube (public web client key). */
const YTMUSIC_API_KEY = 'AIzaSyC9XL3ZjWddXya6X74dJoCTL-WEYFDNX30'
const YTMUSIC_ORIGIN = 'https://music.youtube.com'
const YTMUSIC_API = `${YTMUSIC_ORIGIN}/youtubei/v1`

const CLIENT = {
  clientName: 'WEB_REMIX',
  clientVersion: '1.20250219.01.00',
  hl: 'en',
  gl: 'US',
} as const

/** Innertube search filter params (songs / artists). */
const FILTER_SONGS = 'EgWKAQIIAWoMEA4QChADEAQQCRAF'
const FILTER_ARTISTS = 'EgWKAQIgAWoMEA4QChADEAQQCRAF'

export type YtmSearchResult = {
  id: string
  title: string
  channelTitle: string
  thumbnail: string
  type: 'song' | 'artist' | 'album'
  subtitle?: string
}

export type YtmArtistDetail = {
  id: string
  title: string
  thumbnail: string
  songs: YtmSearchResult[]
  albums: YtmSearchResult[]
}

type JsonObject = Record<string, unknown>

async function ytmusicRequest(
  endpoint: string,
  body: JsonObject,
): Promise<JsonObject> {
  const url = new URL(`${YTMUSIC_API}/${endpoint}`)
  url.searchParams.set('key', YTMUSIC_API_KEY)
  url.searchParams.set('prettyPrint', 'false')

  const res = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Origin: YTMUSIC_ORIGIN,
      'User-Agent':
        'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/133.0.0.0 Safari/537.36',
    },
    body: JSON.stringify({
      context: { client: CLIENT },
      ...body,
    }),
  })

  if (!res.ok) {
    const detail = await res.text()
    throw new Error(`YouTube Music API ${res.status}: ${detail.slice(0, 200)}`)
  }

  return (await res.json()) as JsonObject
}

function runsText(runs: Array<{ text?: string }> | undefined): string {
  if (!runs?.length) return ''
  return runs.map((r) => r.text ?? '').join('').trim()
}

/** Artist line from a song row (stops before album / duration). */
function songArtistLine(
  runs: Array<{ text?: string }> | undefined,
): string {
  if (!runs?.length) return ''
  const parts: string[] = []
  for (const run of runs) {
    if (run.text === ' • ') break
    parts.push(run.text ?? '')
  }
  return parts.join('').trim()
}

function pickMusicThumbnail(thumbnail: unknown): string {
  if (!thumbnail) return ''
  if (typeof thumbnail === 'string') return thumbnail

  function extract(node: unknown, depth = 0): string {
    if (!node || typeof node !== 'object' || depth > 5) return ''
    const obj = node as Record<string, unknown>

    const thumbs = obj.thumbnails as Array<{ url?: string }> | undefined
    if (thumbs?.length) {
      const best = thumbs[thumbs.length - 1] ?? thumbs[0]
      if (best?.url) return best.url
    }

    const nested = [
      obj.musicThumbnailRenderer,
      obj.croppedSquareImageRenderer,
      obj.thumbnail,
      obj.content,
    ]
    for (const child of nested) {
      const url = extract(child, depth + 1)
      if (url) return url
    }

    for (const key of Object.keys(obj)) {
      if (key.endsWith('Renderer') || key === 'thumbnail') {
        const url = extract(obj[key], depth + 1)
        if (url) return url
      }
    }
    return ''
  }

  return extract(thumbnail)
}

function artistThumbnailSource(item: JsonObject): unknown {
  return (
    (item.thumbnailRenderer as { musicThumbnailRenderer?: unknown })
      ?.musicThumbnailRenderer ??
    item.thumbnail ??
  )
}

function watchVideoId(endpoint: unknown): string | null {
  if (!endpoint || typeof endpoint !== 'object') return null
  const watch = (endpoint as { watchEndpoint?: { videoId?: string } })
    .watchEndpoint
  return watch?.videoId ?? null
}

function browseId(endpoint: unknown): string | null {
  if (!endpoint || typeof endpoint !== 'object') return null
  const browse = (endpoint as { browseEndpoint?: { browseId?: string } })
    .browseEndpoint
  return browse?.browseId ?? null
}

function musicVideoTypeFromPlayEndpoint(endpoint: unknown): string | null {
  return (
    endpoint as {
      watchEndpoint?: {
        watchEndpointMusicSupportedConfigs?: {
          watchEndpointMusicConfig?: { musicVideoType?: string }
        }
      }
    }
  )?.watchEndpoint?.watchEndpointMusicSupportedConfigs?.watchEndpointMusicConfig
    ?.musicVideoType ?? null
}

function songVideoType(item: JsonObject): string | null {
  const playEndpoint = (
    item.overlay as {
      musicItemThumbnailOverlayRenderer?: {
        content?: {
          musicPlayButtonRenderer?: {
            playNavigationEndpoint?: unknown
          }
        }
      }
    }
  )?.musicItemThumbnailOverlayRenderer?.content?.musicPlayButtonRenderer
    ?.playNavigationEndpoint

  return musicVideoTypeFromPlayEndpoint(playEndpoint)
}

function songVideoTypeFromTwoRow(item: JsonObject): string | null {
  const playEndpoint = (
    item.thumbnailOverlay as {
      musicItemThumbnailOverlayRenderer?: {
        content?: {
          musicPlayButtonRenderer?: {
            playNavigationEndpoint?: unknown
          }
        }
      }
    }
  )?.musicItemThumbnailOverlayRenderer?.content?.musicPlayButtonRenderer
    ?.playNavigationEndpoint

  return musicVideoTypeFromPlayEndpoint(playEndpoint)
}

/** Audio tracks only — exclude official music videos, UGC, and compilations. */
function isMusicTrackItem(item: JsonObject): boolean {
  const mvType = songVideoType(item) ?? songVideoTypeFromTwoRow(item)
  if (!mvType) return true
  return (
    mvType === 'MUSIC_VIDEO_TYPE_ATV' ||
    mvType === 'MUSIC_VIDEO_TYPE_PRIVATELY_OWNED_TRACK'
  )
}

function parseSongItem(item: JsonObject): YtmSearchResult | null {
  if (!isMusicTrackItem(item)) return null

  const videoId =
    watchVideoId(item.navigationEndpoint) ??
    watchVideoId(
      (
        item.overlay as {
          musicItemThumbnailOverlayRenderer?: {
            content?: {
              musicPlayButtonRenderer?: {
                playNavigationEndpoint?: unknown
              }
            }
          }
        }
      )?.musicItemThumbnailOverlayRenderer?.content?.musicPlayButtonRenderer
        ?.playNavigationEndpoint,
    )

  if (!videoId) return null

  const columns = item.flexColumns as
    | Array<{
        musicResponsiveListItemFlexColumnRenderer?: {
          text?: { runs?: Array<{ text?: string }> }
        }
      }>
    | undefined

  const title = runsText(
    columns?.[0]?.musicResponsiveListItemFlexColumnRenderer?.text?.runs,
  )
  const channelTitle = songArtistLine(
    columns?.[1]?.musicResponsiveListItemFlexColumnRenderer?.text?.runs,
  )

  if (!title) return null

  return {
    id: videoId,
    title,
    channelTitle: channelTitle || 'Unknown artist',
    thumbnail: pickMusicThumbnail(item.thumbnail),
    type: 'song',
  }
}

function parseArtistItem(item: JsonObject): YtmSearchResult | null {
  const id = browseId(item.navigationEndpoint)
  if (!id) return null

  const columns = item.flexColumns as
    | Array<{
        musicResponsiveListItemFlexColumnRenderer?: {
          text?: { runs?: Array<{ text?: string }> }
        }
      }>
    | undefined

  const title = runsText(
    columns?.[0]?.musicResponsiveListItemFlexColumnRenderer?.text?.runs,
  )
  const channelTitle = runsText(
    columns?.[1]?.musicResponsiveListItemFlexColumnRenderer?.text?.runs,
  )

  if (!title) return null

  return {
    id,
    title,
    channelTitle: channelTitle || title,
    thumbnail: pickMusicThumbnail(artistThumbnailSource(item)),
    type: 'artist',
  }
}

function parseSongTwoRow(item: JsonObject): YtmSearchResult | null {
  if (!isMusicTrackItem(item)) return null

  const videoId =
    watchVideoId(item.navigationEndpoint) ??
    watchVideoId(
      (
        item.thumbnailOverlay as {
          musicItemThumbnailOverlayRenderer?: {
            content?: {
              musicPlayButtonRenderer?: {
                playNavigationEndpoint?: unknown
              }
            }
          }
        }
      )?.musicItemThumbnailOverlayRenderer?.content?.musicPlayButtonRenderer
        ?.playNavigationEndpoint,
    )

  if (!videoId) return null

  const title = runsText((item.title as { runs?: Array<{ text?: string }> })?.runs)
  const subtitle = runsText(
    (item.subtitle as { runs?: Array<{ text?: string }> })?.runs,
  )

  if (!title) return null

  return {
    id: videoId,
    title,
    channelTitle: subtitle || 'Unknown artist',
    thumbnail: pickMusicThumbnail(
      (item.thumbnailRenderer as { musicThumbnailRenderer?: unknown })
        ?.musicThumbnailRenderer ?? item.thumbnail,
    ),
    type: 'song',
  }
}

function parseSongEntry(entry: JsonObject): YtmSearchResult | null {
  const list = entry.musicResponsiveListItemRenderer as JsonObject | undefined
  if (list) return parseSongItem(list)

  const twoRow = entry.musicTwoRowItemRenderer as JsonObject | undefined
  if (twoRow) return parseSongTwoRow(twoRow)

  return null
}
function parseAlbumItem(item: JsonObject): YtmSearchResult | null {
  const id = browseId(item.navigationEndpoint)
  if (!id) return null

  const title = runsText((item.title as { runs?: Array<{ text?: string }> })?.runs)
  const subtitle = runsText(
    (item.subtitle as { runs?: Array<{ text?: string }> })?.runs,
  )

  if (!title) return null

  return {
    id,
    title,
    channelTitle: subtitle || 'Album',
    subtitle,
    thumbnail: pickMusicThumbnail(
      (item.thumbnailRenderer as { musicThumbnailRenderer?: unknown })
        ?.musicThumbnailRenderer ?? item.thumbnail,
    ),
    type: 'album',
  }
}

function collectFromShelf(
  shelf: JsonObject,
  kind: 'song' | 'artist',
  out: YtmSearchResult[],
  seen: Set<string>,
) {
  const contents = shelf.contents as Array<JsonObject> | undefined
  if (!contents) return

  for (const entry of contents) {
    const item = entry.musicResponsiveListItemRenderer as JsonObject | undefined
    if (!item) continue

    const parsed =
      kind === 'song' ? parseSongItem(item) : parseArtistItem(item)
    if (!parsed || seen.has(parsed.id)) continue
    seen.add(parsed.id)
    out.push(parsed)
  }
}

function collectSearchResults(
  data: JsonObject,
  kind: 'song' | 'artist',
  limit: number,
): YtmSearchResult[] {
  const results: YtmSearchResult[] = []
  const seen = new Set<string>()

  const tabs = (
    data.contents as {
      tabbedSearchResultsRenderer?: {
        tabs?: Array<{
          tabRenderer?: {
            content?: {
              sectionListRenderer?: { contents?: Array<JsonObject> }
            }
          }
        }>
      }
    }
  )?.tabbedSearchResultsRenderer?.tabs

  for (const tab of tabs ?? []) {
    const sections =
      tab.tabRenderer?.content?.sectionListRenderer?.contents ?? []
    for (const section of sections) {
      const shelf = section.musicShelfRenderer as JsonObject | undefined
      if (shelf) collectFromShelf(shelf, kind, results, seen)

      const card = section.musicCardShelfRenderer as JsonObject | undefined
      if (card && kind === 'song') {
        const cardContents = card.contents as Array<JsonObject> | undefined
        for (const entry of cardContents ?? []) {
          const item = entry.musicResponsiveListItemRenderer as
            | JsonObject
            | undefined
          if (!item) continue
          const parsed = parseSongItem(item)
          if (!parsed || seen.has(parsed.id)) continue
          seen.add(parsed.id)
          results.unshift(parsed)
        }
      }

      if (results.length >= limit) return results.slice(0, limit)
    }
  }

  return results.slice(0, limit)
}

/**
 * The "Top result" card header is YouTube Music's single best-matching entity.
 * Its subtitle's first run states the kind ("Artist", "Song", …) and the title
 * run carries the navigation endpoint we need for the id.
 */
function parseCardHeader(card: JsonObject): YtmSearchResult | null {
  const titleRuns = (card.title as {
    runs?: Array<{ text?: string; navigationEndpoint?: unknown }>
  })?.runs
  const title = runsText(titleRuns)
  if (!title) return null

  const subtitleRuns = (card.subtitle as { runs?: Array<{ text?: string }> })
    ?.runs
  const kind = (subtitleRuns?.[0]?.text ?? '').toLowerCase()
  const thumbnail = pickMusicThumbnail(
    (card.thumbnail as { musicThumbnailRenderer?: unknown })
      ?.musicThumbnailRenderer ?? card.thumbnail,
  )
  const nav = titleRuns?.[0]?.navigationEndpoint ?? card.onTap

  if (kind.startsWith('artist')) {
    const id = browseId(nav)
    if (!id) return null
    return {
      id,
      title,
      channelTitle: runsText(subtitleRuns),
      thumbnail,
      type: 'artist',
    }
  }

  if (kind.startsWith('song')) {
    const videoId = watchVideoId(nav)
    if (!videoId) return null
    return {
      id: videoId,
      title,
      channelTitle: songArtistLine(subtitleRuns) || 'Unknown artist',
      thumbnail,
      type: 'song',
    }
  }

  return null
}

type MixedSearchResults = {
  /** YouTube Music's "Top result" card header (artist or song), if any. */
  topResult: YtmSearchResult | null
  songs: YtmSearchResult[]
  artists: YtmSearchResult[]
}

function collectMixedSearchResults(data: JsonObject): MixedSearchResults {
  const songs: YtmSearchResult[] = []
  const artists: YtmSearchResult[] = []
  const seen = new Set<string>()
  let topResult: YtmSearchResult | null = null

  const tabs = (
    data.contents as {
      tabbedSearchResultsRenderer?: {
        tabs?: Array<{
          tabRenderer?: {
            content?: {
              sectionListRenderer?: { contents?: Array<JsonObject> }
            }
          }
        }>
      }
    }
  )?.tabbedSearchResultsRenderer?.tabs

  for (const tab of tabs ?? []) {
    const sections =
      tab.tabRenderer?.content?.sectionListRenderer?.contents ?? []
    for (const section of sections) {
      const card = section.musicCardShelfRenderer as JsonObject | undefined
      if (card) {
        // The card header is YouTube Music's authoritative top match; its inner
        // contents are typically that entity's related top songs.
        const header = parseCardHeader(card)
        if (header && !seen.has(`${header.type}:${header.id}`)) {
          seen.add(`${header.type}:${header.id}`)
          if (!topResult) topResult = header
          if (header.type === 'song') songs.unshift(header)
          else artists.unshift(header)
        }

        for (const entry of (card.contents as Array<JsonObject> | undefined) ??
          []) {
          const item = entry.musicResponsiveListItemRenderer as
            | JsonObject
            | undefined
          if (!item) continue
          const parsed = parseSongItem(item) ?? parseArtistItem(item)
          if (!parsed || seen.has(`${parsed.type}:${parsed.id}`)) continue
          seen.add(`${parsed.type}:${parsed.id}`)
          if (parsed.type === 'song') songs.push(parsed)
          else artists.push(parsed)
        }
      }

      const shelf = section.musicShelfRenderer as JsonObject | undefined
      if (shelf) {
        for (const entry of (shelf.contents as Array<JsonObject> | undefined) ??
          []) {
          const item = entry.musicResponsiveListItemRenderer as
            | JsonObject
            | undefined
          if (!item) continue
          const parsed = parseSongItem(item) ?? parseArtistItem(item)
          if (!parsed || seen.has(`${parsed.type}:${parsed.id}`)) continue
          seen.add(`${parsed.type}:${parsed.id}`)
          if (parsed.type === 'song') songs.push(parsed)
          else artists.push(parsed)
        }
      }
    }
  }

  return { topResult, songs, artists }
}

function dedupeResults(items: YtmSearchResult[]): YtmSearchResult[] {
  const seen = new Set<string>()
  const out: YtmSearchResult[] = []
  for (const item of items) {
    const key = `${item.type}:${item.id}`
    if (seen.has(key)) continue
    seen.add(key)
    out.push(item)
  }
  return out
}

/** Lowercase, strip punctuation/accents, collapse whitespace for fuzzy matching. */
function normalizeName(value: string): string {
  return value
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\p{L}\p{N}\s]/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim()
}

/**
 * How strongly a result's name matches the query. Higher is better; 0 means no
 * meaningful match. Tuned so exact/prefix/whole-word hits clearly outrank
 * incidental substring matches.
 */
function nameMatchScore(name: string, query: string): number {
  const n = normalizeName(name)
  const q = normalizeName(query)
  if (!n || !q) return 0

  if (n === q) return 100
  if (n.startsWith(q)) return 80

  const words = n.split(' ')
  if (words.includes(q)) return 70
  if (words.some((w) => w.startsWith(q))) return 55

  const qWords = q.split(' ')
  if (qWords.length > 1 && qWords.every((w) => n.includes(w))) return 45
  if (n.includes(q)) return 35

  return 0
}

/**
 * Parse a popularity figure from an artist subtitle such as
 * "Artist • 125M monthly audience" or "910K subscribers" into a raw number.
 */
function parseAudience(text: string): number {
  const m = text.match(
    /([\d.]+)\s*([KMB])?\s*(?:monthly|subscriber|listener|fan|play|view)/i,
  )
  if (!m) return 0
  const value = parseFloat(m[1])
  if (!isFinite(value)) return 0
  const unit = (m[2] ?? '').toUpperCase()
  const mult = unit === 'B' ? 1e9 : unit === 'M' ? 1e6 : unit === 'K' ? 1e3 : 1
  return value * mult
}

/**
 * Pick the single best "Top result".
 *
 * Intent comes from YouTube Music's own top card: if it's an artist, the user is
 * looking for an artist, so we surface the most *popular* well-matching one
 * (e.g. "travis" -> Travis Scott, not an obscure exact-name match). If the card
 * is a song, we keep that song on top (e.g. "rolling in the deep"). Without a
 * usable card we fall back to name-match heuristics.
 */
function withThumbnail(
  item: YtmSearchResult,
  fallback?: string,
): YtmSearchResult {
  if (item.thumbnail || !fallback) return item
  return { ...item, thumbnail: fallback }
}

function chooseTopResult(
  query: string,
  songs: YtmSearchResult[],
  artists: YtmSearchResult[],
  header: YtmSearchResult | null,
  popularity: Map<string, number>,
): YtmSearchResult | null {
  const bestArtist =
    artists
      .map((item) => ({
        item,
        score: nameMatchScore(item.title, query),
        pop: popularity.get(item.id) ?? 0,
      }))
      .filter((x) => x.score >= 55)
      .sort((a, b) => b.pop - a.pop || b.score - a.score)[0]?.item ?? null

  if (header?.type === 'artist') {
    const picked = bestArtist ?? header
    return withThumbnail(picked, header.thumbnail)
  }
  if (header?.type === 'song') {
    return header
  }

  const bestSong = songs
    .map((item) => ({ item, score: nameMatchScore(item.title, query) }))
    .sort((a, b) => b.score - a.score)[0]

  if (bestArtist && (!bestSong || bestSong.score < 80)) return bestArtist
  return bestSong?.item ?? songs[0] ?? bestArtist ?? artists[0] ?? null
}

function browseSections(data: JsonObject): Array<JsonObject> {
  const tabs =
    (data.contents as {
      singleColumnBrowseResultsRenderer?: {
        tabs?: Array<{
          tabRenderer?: {
            content?: {
              sectionListRenderer?: { contents?: Array<JsonObject> }
            }
          }
        }>
      }
    })?.singleColumnBrowseResultsRenderer?.tabs ??
    (data.contents as {
      sectionListRenderer?: { contents?: Array<JsonObject> }
    })?.sectionListRenderer?.contents?.map((section) => ({
      tabRenderer: { content: { sectionListRenderer: { contents: [section] } } },
    }))

  const sections: Array<JsonObject> = []
  for (const tab of tabs ?? []) {
    sections.push(
      ...(tab.tabRenderer?.content?.sectionListRenderer?.contents ?? []),
    )
  }
  return sections
}

function sectionLabel(section: JsonObject): string {
  const shelf = section.musicShelfRenderer as JsonObject | undefined
  if (shelf?.title) {
    return runsText(
      (shelf.title as { runs?: Array<{ text?: string }> })?.runs,
    )
  }

  const carousel = section.musicCarouselShelfRenderer as JsonObject | undefined
  if (carousel) {
    return runsText(
      (carousel.header as {
        musicCarouselShelfBasicHeaderRenderer?: {
          title?: { runs?: Array<{ text?: string }> }
        }
      })?.musicCarouselShelfBasicHeaderRenderer?.title?.runs ??
        (carousel.title as { runs?: Array<{ text?: string }> })?.runs,
    )
  }

  return ''
}

function isNonSongSection(title: string): boolean {
  const t = title.toLowerCase()
  return /album|single|video|podcast|compilation|\bep\b|live performance|interview|shorts|about|related|fans might|similar|featured|playlist|mix|stories|releases you|upcoming|latest release/.test(
    t,
  )
}

function songSectionPriority(title: string): number {
  const t = title.toLowerCase()
  if (/top songs|popular|hits|best known|most popular|trending/.test(t)) return 0
  if (/songs|tracks/.test(t)) return 1
  return 2
}

function collectSongsFromSection(
  section: JsonObject,
  out: YtmSearchResult[],
  seen: Set<string>,
) {
  const shelf = section.musicShelfRenderer as JsonObject | undefined
  if (shelf?.contents) {
    for (const entry of shelf.contents as Array<JsonObject>) {
      const parsed = parseSongEntry(entry)
      if (!parsed || seen.has(parsed.id)) continue
      seen.add(parsed.id)
      out.push(parsed)
    }
  }

  const carousel = section.musicCarouselShelfRenderer as JsonObject | undefined
  if (carousel?.contents) {
    for (const entry of carousel.contents as Array<JsonObject>) {
      const parsed = parseSongEntry(entry)
      if (!parsed || seen.has(parsed.id)) continue
      seen.add(parsed.id)
      out.push(parsed)
    }
  }
}

function collectArtistSongs(data: JsonObject, limit: number): YtmSearchResult[] {
  const results: YtmSearchResult[] = []
  const seen = new Set<string>()
  const sections = browseSections(data)

  const ranked = sections
    .map((section) => ({ section, title: sectionLabel(section) }))
    .filter(({ title }) => !isNonSongSection(title))
    .sort((a, b) => songSectionPriority(a.title) - songSectionPriority(b.title))

  for (const { section } of ranked) {
    collectSongsFromSection(section, results, seen)
    if (results.length >= limit) return results.slice(0, limit)
  }

  return results.slice(0, limit)
}

function findArtistTopSongsEndpoint(
  data: JsonObject,
): { browseId: string; params?: string } | null {
  for (const section of browseSections(data)) {
    const shelf = section.musicShelfRenderer as JsonObject | undefined
    const endpoint = (
      shelf?.bottomEndpoint as {
        browseEndpoint?: {
          browseId?: string
          params?: string
          browseEndpointContextSupportedConfigs?: {
            browseEndpointContextMusicConfig?: { pageType?: string }
          }
        }
      }
    )?.browseEndpoint
    if (!endpoint?.browseId) continue

    const title = runsText(
      (shelf?.title as { runs?: Array<{ text?: string }> })?.runs,
    ).toLowerCase()
    const isPlaylist =
      endpoint.browseEndpointContextSupportedConfigs
        ?.browseEndpointContextMusicConfig?.pageType ===
      'MUSIC_PAGE_TYPE_PLAYLIST'

    if (isPlaylist && /top songs|popular|songs|hits/.test(title)) {
      return { browseId: endpoint.browseId, params: endpoint.params }
    }
  }

  for (const section of browseSections(data)) {
    const endpoint = (
      (section.musicShelfRenderer as JsonObject | undefined)?.bottomEndpoint as {
        browseEndpoint?: {
          browseId?: string
          params?: string
          browseEndpointContextSupportedConfigs?: {
            browseEndpointContextMusicConfig?: { pageType?: string }
          }
        }
      }
    )?.browseEndpoint
    if (
      endpoint?.browseId &&
      endpoint.browseEndpointContextSupportedConfigs
        ?.browseEndpointContextMusicConfig?.pageType === 'MUSIC_PAGE_TYPE_PLAYLIST'
    ) {
      return { browseId: endpoint.browseId, params: endpoint.params }
    }
  }

  return null
}

function playlistShelfFromData(data: JsonObject): JsonObject | null {
  const twoColumn = (
    data.contents as {
      twoColumnBrowseResultsRenderer?: {
        secondaryContents?: {
          sectionListRenderer?: { contents?: Array<JsonObject> }
        }
      }
    }
  )?.twoColumnBrowseResultsRenderer?.secondaryContents?.sectionListRenderer
    ?.contents?.[0]?.musicPlaylistShelfRenderer

  if (twoColumn) return twoColumn as JsonObject

  const primary = (
    data.contents as {
      singleColumnBrowseResultsRenderer?: {
        tabs?: Array<{
          tabRenderer?: {
            content?: {
              sectionListRenderer?: { contents?: Array<JsonObject> }
            }
          }
        }>
      }
    }
  )?.singleColumnBrowseResultsRenderer?.tabs?.[0]?.tabRenderer?.content
    ?.sectionListRenderer?.contents?.[0]?.musicPlaylistShelfRenderer

  return (
    (primary as JsonObject | undefined) ??
    (data.continuationContents as { musicPlaylistShelfContinuation?: JsonObject })
      ?.musicPlaylistShelfContinuation ??
    null
  )
}

function extractPlaylistContinuation(data: JsonObject): string | null {
  const shelf = playlistShelfFromData(data)
  if (!shelf) return null

  const fromContinuations = (
    shelf.continuations as Array<{
      nextContinuationData?: { continuation?: string }
    }> | undefined
  )?.[0]?.nextContinuationData?.continuation
  if (fromContinuations) return fromContinuations

  for (const entry of (shelf.contents as Array<JsonObject> | undefined) ?? []) {
    const token = (
      entry.continuationItemRenderer as {
        continuationEndpoint?: {
          continuationCommand?: { token?: string }
        }
      }
    )?.continuationEndpoint?.continuationCommand?.token
    if (token) return token
  }

  return null
}

function collectPlaylistShelfSongs(
  data: JsonObject,
  out: YtmSearchResult[],
  seen: Set<string>,
) {
  const shelf = playlistShelfFromData(data)
  if (!shelf?.contents) return

  for (const entry of shelf.contents as Array<JsonObject>) {
    const item = entry.musicResponsiveListItemRenderer as JsonObject | undefined
    if (!item) continue
    const parsed = parseSongItem(item)
    if (!parsed || seen.has(parsed.id)) continue
    seen.add(parsed.id)
    out.push(parsed)
  }
}

const MAX_ARTIST_SONG_PAGES = 50

async function fetchPaginatedPlaylistSongs(
  browseId: string,
  params?: string,
): Promise<YtmSearchResult[]> {
  const results: YtmSearchResult[] = []
  const seen = new Set<string>()

  let data = await ytmusicRequest(
    'browse',
    params ? { browseId, params } : { browseId },
  )
  collectPlaylistShelfSongs(data, results, seen)

  let continuation = extractPlaylistContinuation(data)
  let pages = 1
  while (continuation && pages < MAX_ARTIST_SONG_PAGES) {
    data = await ytmusicRequest('browse', { continuation })
    collectPlaylistShelfSongs(data, results, seen)
    continuation = extractPlaylistContinuation(data)
    pages++
  }

  return results
}

async function fetchAllArtistSongs(
  browseId: string,
  artistData?: JsonObject,
): Promise<YtmSearchResult[]> {
  const data = artistData ?? (await ytmusicRequest('browse', { browseId }))
  const playlist = findArtistTopSongsEndpoint(data)

  if (playlist) {
    const songs = await fetchPaginatedPlaylistSongs(
      playlist.browseId,
      playlist.params,
    )
    if (songs.length > 0) return songs
  }

  return collectArtistSongs(data, 500)
}

function collectArtistTopSongs(
  data: JsonObject,
  limit: number,
): YtmSearchResult[] {
  return collectArtistSongs(data, limit)
}

function collectArtistDetail(
  data: JsonObject,
  songs: YtmSearchResult[],
): YtmArtistDetail {
  const header = (
    data.header as {
      musicImmersiveHeaderRenderer?: {
        title?: { runs?: Array<{ text?: string }> }
        thumbnail?: unknown
      }
      musicVisualHeaderRenderer?: {
        title?: { runs?: Array<{ text?: string }> }
        thumbnail?: unknown
      }
    }
  )?.musicImmersiveHeaderRenderer ??
    (data.header as { musicVisualHeaderRenderer?: unknown })
      ?.musicVisualHeaderRenderer

  const title = runsText(
    (header as { title?: { runs?: Array<{ text?: string }> } })?.title?.runs,
  )
  const thumbnail = pickMusicThumbnail(
    (header as { thumbnail?: unknown })?.thumbnail,
  )

  return {
    id: '',
    title: title || 'Artist',
    thumbnail,
    songs,
    albums: [],
  }
}

function collectAlbumTracks(data: JsonObject, limit: number): YtmSearchResult[] {
  const results: YtmSearchResult[] = []
  const seen = new Set<string>()

  for (const section of browseSections(data)) {
    const shelf = section.musicShelfRenderer as JsonObject | undefined
    if (shelf) collectFromShelf(shelf, 'song', results, seen)
    if (results.length >= limit) break
  }

  return results.slice(0, limit)
}

export type YtmChartPlaylist = {
  title: string
  browseId: string
  thumbnail: string
}

export type YtmMoodCategory = {
  title: string
  params: string
}

export type YtmMoodSection = {
  title: string
  categories: YtmMoodCategory[]
}

export type YtmDiscover = {
  country: string
  countries: string[]
  trending: YtmSearchResult[]
  charts: YtmChartPlaylist[]
  moods: YtmMoodSection[]
}

function parseChartCountryOptions(data: JsonObject): string[] {
  const mutations =
    (
      data.frameworkUpdates as {
        entityBatchUpdate?: {
          mutations?: Array<{
            payload?: {
              musicFormBooleanChoice?: { opaqueToken?: string }
            }
          }>
        }
      }
    )?.entityBatchUpdate?.mutations ?? []

  const options = mutations
    .map((m) => m.payload?.musicFormBooleanChoice?.opaqueToken)
    .filter((code): code is string => typeof code === 'string' && code.length === 2)

  return [...new Set(options)]
}

function isSongChartTitle(title: string): boolean {
  const t = title.toLowerCase()
  if (/\bvideo\b|\bmv\b|\bshorts\b/.test(t)) return false
  return /\bsong|\btop|\bdaily|\bchart|\btrending|\b100\b/.test(t)
}

function normalizeChartTitle(title: string, country: string): string {
  if (country === 'ZZ') {
    return title
      .replace(/\bUnited States\b/i, 'Worldwide')
      .replace(/\bUS\b(?=\s*$|\s*[-–—])/i, 'Worldwide')
      .replace(/\(\s*US\s*\)/i, '(Worldwide)')
  }
  return title
}

function parseChartPlaylists(
  data: JsonObject,
  country = 'ZZ',
): YtmChartPlaylist[] {
  const playlists: YtmChartPlaylist[] = []
  const seen = new Set<string>()

  for (const section of browseSections(data)) {
    const carousel = section.musicCarouselShelfRenderer as JsonObject | undefined
    if (!carousel?.contents) continue

    const label = sectionLabel(section).toLowerCase()
    if (!/chart|daily|top|trending/.test(label)) continue
    if (/\bvideo\b|\bmv\b/.test(label)) continue

    for (const entry of carousel.contents as Array<JsonObject>) {
      const row = entry.musicTwoRowItemRenderer as JsonObject | undefined
      if (!row) continue

      const playlistBrowseId = browseIdFromNav(row.navigationEndpoint)
      if (!playlistBrowseId?.startsWith('VL') || seen.has(playlistBrowseId)) continue
      seen.add(playlistBrowseId)

      const rawTitle = runsText(
        (row.title as { runs?: Array<{ text?: string }> })?.runs,
      )
      if (!rawTitle || !isSongChartTitle(rawTitle)) continue

      playlists.push({
        title: normalizeChartTitle(rawTitle, country),
        browseId: playlistBrowseId,
        thumbnail: pickMusicThumbnail(
          (row.thumbnailRenderer as { musicThumbnailRenderer?: unknown })
            ?.musicThumbnailRenderer ?? row.thumbnail,
        ),
      })
    }
  }

  return playlists
}

function browseIdFromNav(endpoint: unknown): string | null {
  return (
    browseId(endpoint) ??
    (
      endpoint as {
        browseEndpoint?: { browseId?: string }
      }
    )?.browseEndpoint?.browseId ??
    null
  )
}

function collectCarouselSongs(
  section: JsonObject,
  limit: number,
): YtmSearchResult[] {
  const carousel = section.musicCarouselShelfRenderer as JsonObject | undefined
  if (!carousel?.contents) return []

  const results: YtmSearchResult[] = []
  const seen = new Set<string>()

  for (const entry of carousel.contents as Array<JsonObject>) {
    const parsed = parseSongEntry(entry)
    if (!parsed || parsed.type !== 'song' || seen.has(parsed.id)) continue
    seen.add(parsed.id)
    results.push(parsed)
    if (results.length >= limit) break
  }

  return results
}

function parseMoodCategories(data: JsonObject): YtmMoodSection[] {
  const sections: YtmMoodSection[] = []

  for (const section of browseSections(data)) {
    const grid = section.gridRenderer as JsonObject | undefined
    if (!grid?.items) continue

    const title = runsText(
      (grid.header as {
        gridHeaderRenderer?: { title?: { runs?: Array<{ text?: string }> } }
      })?.gridHeaderRenderer?.title?.runs,
    )

    const categories: YtmMoodCategory[] = []
    for (const entry of grid.items as Array<JsonObject>) {
      const button = entry.musicNavigationButtonRenderer as JsonObject | undefined
      if (!button) continue

      const params = (
        button.clickCommand as {
          browseEndpoint?: { params?: string }
        }
      )?.browseEndpoint?.params

      const categoryTitle = runsText(
        (button.buttonText as { runs?: Array<{ text?: string }> })?.runs,
      )

      if (!params || !categoryTitle) continue
      categories.push({ title: categoryTitle, params })
    }

    if (categories.length > 0) {
      sections.push({ title: title || 'Browse', categories })
    }
  }

  return sections
}

function parseMoodPlaylists(data: JsonObject): YtmChartPlaylist[] {
  const playlists: YtmChartPlaylist[] = []
  const seen = new Set<string>()

  for (const section of browseSections(data)) {
    const carousel = section.musicCarouselShelfRenderer as JsonObject | undefined
    const grid = section.gridRenderer as JsonObject | undefined
    const entries = (carousel?.contents ?? grid?.items ?? []) as Array<JsonObject>

    for (const entry of entries) {
      const row = entry.musicTwoRowItemRenderer as JsonObject | undefined
      if (!row) continue

      const playlistBrowseId = browseIdFromNav(row.navigationEndpoint)
      if (!playlistBrowseId || seen.has(playlistBrowseId)) continue
      seen.add(playlistBrowseId)

      const title = runsText(
        (row.title as { runs?: Array<{ text?: string }> })?.runs,
      )
      if (!title) continue

      playlists.push({
        title,
        browseId: playlistBrowseId,
        thumbnail: pickMusicThumbnail(
          (row.thumbnailRenderer as { musicThumbnailRenderer?: unknown })
            ?.musicThumbnailRenderer ?? row.thumbnail,
        ),
      })
    }
  }

  return playlists
}

export async function fetchYtmExploreTrending(
  limit = 12,
): Promise<YtmSearchResult[]> {
  const data = await ytmusicRequest('browse', { browseId: 'FEmusic_explore' })

  for (const section of browseSections(data)) {
    const label = sectionLabel(section).toLowerCase()
    if (!/trending/.test(label)) continue
    const songs = collectCarouselSongs(section, limit)
    if (songs.length > 0) return songs
  }

  return []
}

export async function fetchYtmCharts(
  country = 'ZZ',
): Promise<{ country: string; countries: string[]; playlists: YtmChartPlaylist[] }> {
  const data = await ytmusicRequest('browse', {
    browseId: 'FEmusic_charts',
    formData: { selectedValues: [country] },
  })

  return {
    country,
    countries: parseChartCountryOptions(data),
    playlists: parseChartPlaylists(data, country),
  }
}

export async function fetchYtmMoodCategories(): Promise<YtmMoodSection[]> {
  const data = await ytmusicRequest('browse', {
    browseId: 'FEmusic_moods_and_genres',
  })
  return parseMoodCategories(data)
}

export async function fetchYtmMoodPlaylists(
  params: string,
): Promise<YtmChartPlaylist[]> {
  const data = await ytmusicRequest('browse', {
    browseId: 'FEmusic_moods_and_genres_category',
    params,
  })
  return parseMoodPlaylists(data)
}

export async function fetchYtmPlaylistTracks(
  browseId: string,
  limit = 30,
): Promise<YtmSearchResult[]> {
  const songs = await fetchPaginatedPlaylistSongs(browseId)
  return songs.slice(0, limit)
}

export async function fetchYtmDiscover(country = 'ZZ'): Promise<YtmDiscover> {
  const [trending, charts, moods] = await Promise.all([
    fetchYtmExploreTrending(10),
    fetchYtmCharts(country),
    fetchYtmMoodCategories(),
  ])

  return {
    country: charts.country,
    countries: charts.countries,
    trending,
    charts: charts.playlists,
    moods,
  }
}

export const SEARCH_SONG_LIMIT = 40
export const SEARCH_ARTIST_LIMIT = 30
export const SEARCH_ALL_LIMIT = 60
export const SEARCH_ALL_ARTIST_SLOTS = 10
export const ARTIST_TRACKS_LIMIT = 80

export async function searchYtmSongs(
  query: string,
  limit = SEARCH_SONG_LIMIT,
): Promise<YtmSearchResult[]> {
  const data = await ytmusicRequest('search', {
    query,
    params: FILTER_SONGS,
  })
  return collectSearchResults(data, 'song', limit)
}

export async function searchYtmArtists(
  query: string,
  limit = SEARCH_ARTIST_LIMIT,
): Promise<YtmSearchResult[]> {
  const data = await ytmusicRequest('search', {
    query,
    params: FILTER_ARTISTS,
  })
  return collectSearchResults(data, 'artist', limit)
}

export async function searchYtmAll(
  query: string,
  limit = SEARCH_ALL_LIMIT,
): Promise<YtmSearchResult[]> {
  // Up to this many artist slots are reserved so artists are never crowded
  // out by the (typically far more numerous) song results.
  const ARTIST_SLOTS = SEARCH_ALL_ARTIST_SLOTS

  const [mixedData, songData, artistData] = await Promise.all([
    ytmusicRequest('search', { query }),
    ytmusicRequest('search', { query, params: FILTER_SONGS }),
    ytmusicRequest('search', { query, params: FILTER_ARTISTS }),
  ])

  const mixed = collectMixedSearchResults(mixedData)
  const filterSongs = collectSearchResults(songData, 'song', limit)
  const filterArtists = collectSearchResults(artistData, 'artist', ARTIST_SLOTS + 2)

  // Mixed results are relevance-ranked by YouTube Music, so they lead; the
  // dedicated filter searches backfill so each type is well represented.
  const songs = dedupeResults([...mixed.songs, ...filterSongs])

  // Popularity (monthly audience / subscribers) parsed from each artist's
  // subtitle, used to rank the top artist and order the Artists list.
  const popularity = new Map<string, number>()
  for (const a of [...mixed.artists, ...filterArtists]) {
    const pop = parseAudience(a.channelTitle ?? '')
    if (pop > (popularity.get(a.id) ?? 0)) popularity.set(a.id, pop)
  }
  const artists = dedupeResults([...mixed.artists, ...filterArtists]).sort(
    (a, b) => (popularity.get(b.id) ?? 0) - (popularity.get(a.id) ?? 0),
  )

  // Decide the single best match using YouTube Music's card intent + popularity.
  const top = chooseTopResult(query, songs, artists, mixed.topResult, popularity)
  const topKey = top ? `${top.type}:${top.id}` : null

  const artistCount = Math.min(artists.length, ARTIST_SLOTS)
  const songCount = Math.max(0, limit - artistCount)
  let pickedSongs = songs.slice(0, songCount)
  let pickedArtists = artists.slice(0, artistCount)

  // Guarantee the chosen top survives the per-type slicing above.
  if (top && topKey) {
    if (
      top.type === 'song' &&
      !pickedSongs.some((s) => `song:${s.id}` === topKey)
    ) {
      pickedSongs = [top, ...pickedSongs].slice(0, songCount)
    }
    if (
      top.type === 'artist' &&
      !pickedArtists.some((a) => `artist:${a.id}` === topKey)
    ) {
      pickedArtists = [top, ...pickedArtists].slice(0, artistCount)
    }
  }

  // Top result leads; dedupe drops its duplicate from the type lists.
  const combined = dedupeResults([
    ...(top ? [top] : []),
    ...pickedSongs,
    ...pickedArtists,
  ])

  return combined.slice(0, limit)
}

export async function fetchYtmArtistTracks(
  browseId: string,
  limit = ARTIST_TRACKS_LIMIT,
): Promise<YtmSearchResult[]> {
  const songs = await fetchAllArtistSongs(browseId)
  return songs.slice(0, limit)
}

export async function fetchYtmArtistDetail(
  browseId: string,
): Promise<YtmArtistDetail> {
  const artistData = await ytmusicRequest('browse', { browseId })
  const songs = await fetchAllArtistSongs(browseId, artistData)
  const detail = collectArtistDetail(artistData, songs)
  return { ...detail, id: browseId, title: detail.title || 'Artist' }
}

export async function fetchYtmAlbumTracks(
  browseId: string,
  limit = 50,
): Promise<YtmSearchResult[]> {
  const data = await ytmusicRequest('browse', { browseId })
  return collectAlbumTracks(data, limit)
}
